// ── AI PANEL ─────────────────────────────────────────────────
const TAB_CLASSES=['active-b','active-p','active-a','active-g'];

function renderPanel(){
  const el=document.getElementById('aip-cards');
  el.style.opacity='0';el.style.transform='translateX(8px)';
  setTimeout(()=>{
    el.innerHTML=DATA[activeQi][sets[activeQi]].map((c,i)=>{
      const cls=c.pri==='high'?'qc-red':c.pri==='med'?'qc-amb':'qc-grn';
      return `<div class="aip-card ${cls}" style="animation-delay:${i*65}ms">
        <div class="qc-head">${c.head}</div>
        <div class="qc-text">${c.text}</div>
      </div>`;
    }).join('');
    updatePanelDots();
    requestAnimationFrame(()=>{el.style.opacity='1';el.style.transform='translateX(0)'});
  },200);
}

// Live clock
function updateClock(){
  const t=document.getElementById('pl-time');
  if(t){const n=new Date();t.textContent=n.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',second:'2-digit'});}
}
setInterval(updateClock,1000);updateClock();

function updatePanelDots(){
  document.getElementById('aip-dots').querySelectorAll('.aip-dot')
    .forEach((d,i)=>d.classList.toggle('active',i===sets[activeQi]));
}

function updateTabs(){
  document.querySelectorAll('.aip-tab').forEach((t,i)=>{
    t.className=`aip-tab aip-tab-${['b','p','a','g'][i]}`;
    if(i===activeQi)t.classList.add(TAB_CLASSES[activeQi]);
  });
  // highlight matching card
  [0,1,2,3].forEach(i=>{
    const c=document.getElementById('card-'+i);
    if(c)c.classList.toggle('seg-active',i===activeQi);
  });
}

function setActive(qi){
  activeQi=qi;
  updateTabs();
  renderPanel();
}

function shufflePanel(){
  sets[activeQi]=(sets[activeQi]+1)%3;
  renderPanel();
}

// ── CARD HOVER ────────────────────────────────────────────────
function setHover(qi){
  [0,1,2,3].forEach(i=>document.getElementById('card-'+i)?.classList.toggle('seg-active',i===qi||i===activeQi));
}
function clearHover(){
  [0,1,2,3].forEach(i=>{
    const c=document.getElementById('card-'+i);
    if(c)c.classList.toggle('seg-active',i===activeQi);
  });
}

