let overlayQi=null;

function renderOvCards(qi){
  return DATA[qi][sets[qi]].map((c,i)=>{
    const cls=c.pri==='high'?'ov-red':c.pri==='med'?'ov-amb':'ov-grn';
    return `<div class="ov-card ${cls}" style="animation-delay:${i*65}ms">
      <div class="ov-card-head">${c.head}</div>
      <div class="ov-card-text">${c.text}</div>
    </div>`;
  }).join('');
}
function ovDots(qi){return[0,1,2].map(i=>`<div class="q-dot${i===sets[qi]?' active':''}"></div>`).join('');}

function expandQ(qi){
  overlayQi=qi;const m=MODULES[qi];
  const panel=document.getElementById('ov-panel');
  panel.className=`ov-panel ov-${m.cls}`;
  panel.innerHTML=`<div class="ov-head"><div class="ov-icon">${m.icon}</div><div class="ov-info"><div class="ov-name">${m.name}</div><div class="ov-desc">${m.desc}</div></div><button class="ov-close" onclick="closeOverlay()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><div class="ov-div"></div><div class="ov-ins"><div class="ov-ins-bar"><div class="ov-ins-ico"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2a7 7 0 017 7c0 2.38-1.19 4.47-3 5.74V17a1 1 0 01-1 1H9a1 1 0 01-1-1v-2.26C6.19 13.47 5 11.38 5 9a7 7 0 017-7z"/><path d="M9 21h6"/></svg></div><span class="ov-ins-lbl">AI Insights</span><span class="ov-spacer"></span><div class="q-dots" id="ov-dots" style="margin-right:8px">${ovDots(qi)}</div><button class="ov-shuffle" onclick="shuffleOv()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="16 3 21 3 21 8"/><line x1="4" y1="20" x2="21" y2="3"/><polyline points="21 16 21 21 16 21"/><line x1="15" y1="15" x2="21" y2="21"/><line x1="4" y1="4" x2="9" y2="9"/></svg></button></div><div class="ov-cards" id="ov-cards">${renderOvCards(qi)}</div></div>`;
  document.getElementById('overlay').classList.add('open');
}
function shuffleOv(){
  if(overlayQi===null)return;
  const el=document.getElementById('ov-cards');
  el.style.opacity='0';el.style.transform='scale(.97)';
  setTimeout(()=>{
    sets[overlayQi]=(sets[overlayQi]+1)%3;
    el.innerHTML=renderOvCards(overlayQi);
    document.getElementById('ov-dots').innerHTML=ovDots(overlayQi);
    requestAnimationFrame(()=>{el.style.opacity='1';el.style.transform='scale(1)'});
  },200);
}
function closeOverlay(){document.getElementById('overlay').classList.remove('open');setTimeout(()=>{overlayQi=null},380);}
function handleOverlayClick(e){if(e.target===document.getElementById('overlay'))closeOverlay();}
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeOverlay()});

