function buildWorklist(filter='all'){
  const tb = document.getElementById('wl-body');
  if(!tb) return;
  const rows = filter==='all' ? WL_DATA : WL_DATA.filter(r=>r.cat===filter);
  document.getElementById('wl-count').textContent = rows.length;
  tb.innerHTML = rows.map(r=>{
    const pc  = r.pri==='H'?'p-h': r.pri==='M'?'p-m':'p-l';
    const pl  = r.pri==='H'?'High': r.pri==='M'?'Medium':'Low';
    const ageCls = r.age>120?'bad': r.age>60?'w':'ok';
    const amtCls = r.pri==='H'?'bad': r.pri==='M'?'w':'ok';
    const catCls = {denial:'t-dn',appeal:'t-ap',coding:'t-bl',collections:'t-ar'}[r.cat]||'t-ar';
    return `<tr data-cat="${r.cat}" class="${r.demoIdx ? 'wl-demo' : ''}" ${r.demoIdx ? `onclick="if(typeof openCase==='function')openCase(${r.demoIdx});else if(typeof openCaseCoder==='function')openCaseCoder(${r.demoIdx});" style="cursor:pointer"` : ''}>
      <td><span class="wl-val" style="font-size:10.5px;letter-spacing:-.2px;">${r.cl}</span></td>
      <td>
        <div style="font-size:11px;font-weight:600;color:var(--text);font-family:'Plus Jakarta Sans',sans-serif;">${r.pt}</div>
        <div style="font-size:9.5px;color:var(--text4);font-family:'Plus Jakarta Sans',sans-serif;margin-top:1px;">${r.fac}${r.fac.endsWith('Facility') || r.fac.indexOf('Center') > -1 || r.fac.indexOf('Care') > -1 || r.fac.indexOf('GI') > -1 || r.fac.indexOf('Sports') > -1 || r.fac.indexOf('Vascular') > -1 ? '' : ' Facility'}</div>
      </td>
      <td><div style="font-size:10px;color:var(--text3);font-family:'DM Mono',monospace;max-width:100px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${r.pyr}</div></td>
      <td>
        <div style="display:flex;align-items:flex-start;gap:6px;">
          <span class="wl-type ${catCls}" style="flex-shrink:0;margin-top:1px;">${r.cat}</span>
          <span style="font-size:10.5px;color:var(--text2);font-family:'Plus Jakarta Sans',sans-serif;line-height:1.4;">${r.act}</span>
        </div>
      </td>
      <td style="text-align:right"><span class="wl-val ${amtCls}">${r.amt}</span></td>
      <td style="text-align:right"><span class="wl-val ${ageCls}">${r.age}d</span></td>
      <td style="text-align:center"><span class="pri ${pc}">${pl}</span></td>
    </tr>`;
  }).join('');
}
buildWorklist();

