/* ── KPI COUNTER ANIMATION ── */
function animateKPI(el, target, duration=1100){
  const isFloat  = String(target).includes('.');
  const useComma = el.dataset.comma === 'true';
  const sfx = el.dataset.sfx || '';
  const pfx = el.dataset.pfx || '';
  let start = null;
  function step(ts){
    if(!start) start = ts;
    const progress = Math.min((ts-start)/duration, 1);
    const ease = 1 - Math.pow(1-progress, 3);
    const val = target * ease;
    let display;
    if(useComma)     display = Math.round(val).toLocaleString();
    else if(isFloat) display = val.toFixed(2);
    else             display = Math.round(val);
    el.textContent = pfx + display + sfx;
    if(progress < 1) requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}
document.querySelectorAll('.kc-val[data-target]').forEach((el,idx)=>{
  setTimeout(()=> animateKPI(el, parseFloat(el.dataset.target)), idx * 120);
});

