/* ═══ MAIN TAB SWITCHER ═══ */
function switchMainTab(tab) {
  document.querySelectorAll('.ptab[data-tab]').forEach(t => t.classList.remove('active'));
  const activeTab = document.querySelector('.ptab[data-tab="' + tab + '"]');
  if (activeTab) activeTab.classList.add('active');
  document.querySelectorAll('.main-panel').forEach(p => p.classList.remove('active'));
  const activePanel = document.getElementById('main-' + tab);
  if (activePanel) activePanel.classList.add('active');
  const bcCur = document.querySelector('.bc-cur');
  if (bcCur) {
    const labels = { summary:'Executive Summary', claims:'Claims Workbench', roi:'ROI Report' };
    bcCur.textContent = labels[tab] || tab;
  }
  if (tab === 'roi') { showRoiSlide(1); }
  if (tab === 'claims') {
    document.querySelectorAll('.claims-sub').forEach(el => el.classList.remove('active'));
    const cl = document.getElementById('view-claims');
    if (cl) cl.classList.add('active');
  }
}
document.querySelectorAll('.ptab[data-tab]').forEach(tab => {
  tab.addEventListener('click', function() { switchMainTab(this.dataset.tab); });
});


