function ri(a,b){return Math.floor(Math.random()*(b-a+1))+a}
function pick(a){return a[ri(0,a.length-1)]}
function fmtD(n){const d=new Date();d.setDate(d.getDate()-n);return d.toLocaleDateString('en-US',{month:'2-digit',day:'2-digit',year:'numeric'})}
function fmtU(n){return '$'+n.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}

const SEED=Array.from({length:30},(_,i)=>{
  const opp=i<12?'High':i<22?'Medium':'Low';
  const cat=CATS[i%CATS.length];
  const payer=PAYERS[i%PAYERS.length];
  const cptKey=CPT_POOL[i%CPT_POOL.length];
  const cd=CPT_DATA[cptKey];
  /* Value: PFS base rate ± minor facility/modifier variance (realistic per-claim variation) */
  const varPct=0.92+((i*37)%16)*0.008; /* 92%–104% of PFS rate */
  const val=Math.round(cd.val*varPct*100)/100;
  const cpl=[72,80,85,90,95,100][i%6];
  const status=STATUSES[i%STATUSES.length];
  /* Errors/warnings tied to category (deterministic, not random) */
  const errs=cat==='Coding'||cat==='Eligibility'||cat==='Authorization'||cat==='Prior Auth'||cat==='Clearing House'?1:0;
  const warns=cat==='COB'||cat==='Patient'||cat==='Payer Policy'||cat==='Manager Review'||cat==='Capitation'||cat==='Insurance Accepted'?1:0;
  const svcAgo=10+(i*6)%110;
  const daysLeft=status==='Submitted'||status==='Approved'?null:30+(i*13)%150;
  const npi=NPI_POOL[i];
  const bnpi=BNPI_POOL[i%BNPI_POOL.length];
  /* Massachusetts Medicaid member ID format: 2 alpha + 6 digit */
  const mb=`AU${String(100847+i*1283).slice(-6)}`;
  /* OHP group code format */
  const grp=`OHP-CCO-${String(47000+i*17).slice(-5)}`;
  /* Auth number only when no blocking errors — OHP PA format */
  const auth=errs===0?`OHP-PA-${String(206000+i*97).slice(-6)}-R`:null;
  const patient=`${FN[i]} ${LN[i]}`;
  const addr=ADDRS[i%ADDRS.length];
  const dob=DOB_POOL[i];
  const taxId=TAXID_POOL[i%TAXID_POOL.length];
  return{
    idx:i, id:`52${6000+i+33}`, patient, payer, cat, opp, val, cpl, status, errs, warns,
    svcDate:fmtD(svcAgo), submittedDate:fmtD(svcAgo-3), daysLeft,
    cpt:cptKey, cptDesc:cd.desc, pos:cd.pos,
    icd:cd.icd, icdDesc:cd.icdDesc,
    icd2:cd.icd2, icd2Desc:cd.icd2Desc,
    npi, bnpi, mb, grp, auth, addr, dob, taxId,
    referring:{name:'DR. SARAH E. CHEN, MD', npi:'1568473920', specialty:'Internal Medicine'},
    facility:{name:'METROHEALTH DOWNTOWN SPECIALTY CENTER', addr:'1 BROOKLINE AVE, BOSTON MA 02215', npi:'1093847625'},
    billing:{name:'METROHEALTH REVENUE SERVICES LLC', phone:'(617) 555-0192', npi:'1245670812'},
  };
});

